proof fn phi_5_execute_disable_bit63_overlaps_addr(v: usize)
    requires
        v == 0x8000_0000_0000_1000usize,
    ensures
        usize2execute_disable(v) == true,
        spec_usize2pa(v) == 0x0000_0000_0000_1000usize,
        MEM_valid(spec_usize2pa(v)),
{
    assert(0x8000_0000_0000_1000usize & (0x1u64 << 63u64) as usize != 0) by (bit_vector);
    assert(0x8000_0000_0000_1000usize & 0x0000_ffff_ffff_f000u64 as usize == 0x0000_0000_0000_1000usize) by (bit_vector);
    assert(0x0000_0000_0000_1000usize & (!0x0000_ffff_ffff_f000u64) as usize == 0) by (bit_vector);
}
